#define MA_U1LCR_UART1         0x00000003  /* UART1 Line Control Register */
#define MA_U1LCR_UART1_MASK    0x000000FF  /* Used bits */
#define MA_U1MCR_UART1         0x00000000  /* UART1 Modem Control Register */
